// src/components/EligibilityChecker.js - Matching Your Exact Design
import React, { useState, useEffect } from 'react';
import { Upload, FileText, CheckCircle, XCircle, AlertCircle, ChevronDown } from 'lucide-react';

const EligibilityChecker = ({ token }) => {
  const [patients, setPatients] = useState([]);
  const [trials, setTrials] = useState([]);
  
  // Patient inputs
  const [patientMode, setPatientMode] = useState('dropdown'); // 'dropdown', 'text', 'pdf'
  const [selectedPatientId, setSelectedPatientId] = useState('');
  const [patientText, setPatientText] = useState('');
  const [patientFile, setPatientFile] = useState(null);
  
  // Trial inputs
  const [trialMode, setTrialMode] = useState('dropdown'); // 'dropdown', 'text', 'pdf'
  const [selectedTrialId, setSelectedTrialId] = useState('');
  const [trialText, setTrialText] = useState('');
  const [trialFile, setTrialFile] = useState(null);
  
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    loadPatientsAndTrials();
  }, [token]);

  const loadPatientsAndTrials = async () => {
    try {
      const [patientsRes, trialsRes] = await Promise.all([
        fetch('http://localhost:8000/api/patients', {
          headers: { 'Authorization': `Bearer ${token}` }
        }),
        fetch('http://localhost:8000/api/trials', {
          headers: { 'Authorization': `Bearer ${token}` }
        })
      ]);
      
      const patientsData = await patientsRes.json();
      const trialsData = await trialsRes.json();
      
      // Ensure data is always an array
      setPatients(Array.isArray(patientsData) ? patientsData : []);
      setTrials(Array.isArray(trialsData) ? trialsData : []);
      
      console.log('Patients loaded:', patientsData);
      console.log('Trials loaded:', trialsData);
    } catch (err) {
      console.error('Failed to load data:', err);
      setPatients([]);
      setTrials([]);
    }
  };

  const handleCheck = async () => {
    setError('');
    setLoading(true);
    setResult(null);

    try {
      const formData = new FormData();

      // Handle patient input
      if (patientMode === 'dropdown') {
        if (!selectedPatientId) throw new Error('Please select a patient');
        formData.append('patient_id', selectedPatientId);
      } else if (patientMode === 'text') {
        if (!patientText) throw new Error('Please enter patient information');
        formData.append('patient_text', patientText);
      } else if (patientMode === 'pdf') {
        if (!patientFile) throw new Error('Please upload patient PDF');
        formData.append('patient_pdf', patientFile);
      }

      // Handle trial input
      if (trialMode === 'dropdown') {
        if (!selectedTrialId) throw new Error('Please select a trial');
        formData.append('trial_id', selectedTrialId);
      } else if (trialMode === 'text') {
        if (!trialText) throw new Error('Please enter trial criteria');
        formData.append('trial_text', trialText);
      } else if (trialMode === 'pdf') {
        if (!trialFile) throw new Error('Please upload trial PDF');
        formData.append('trial_pdf', trialFile);
      }

      const response = await fetch('http://localhost:8000/api/eligibility/check', {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}` },
        body: formData
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Eligibility check failed');
      }

      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status) => {
    switch(status) {
      case 'eligible': return CheckCircle;
      case 'not_eligible': return XCircle;
      default: return AlertCircle;
    }
  };

  const getStatusColor = (status) => {
    switch(status) {
      case 'eligible': return '#10b981';
      case 'not_eligible': return '#ef4444';
      default: return '#f59e0b';
    }
  };

  const styles = {
    container: { padding: '40px', color: 'white' },
    title: { 
      fontSize: '48px', 
      fontWeight: '800',
      background: 'linear-gradient(135deg, #22d3ee 0%, #3b82f6 100%)',
      WebkitBackgroundClip: 'text',
      WebkitTextFillColor: 'transparent',
      marginBottom: '40px'
    },
    twoColumnGrid: {
      display: 'grid',
      gridTemplateColumns: '1fr 1fr',
      gap: '32px',
      marginBottom: '32px'
    },
    section: {
      background: 'rgba(30, 41, 59, 0.6)',
      backdropFilter: 'blur(10px)',
      padding: '32px',
      borderRadius: '24px',
      border: '1px solid rgba(100,116,139,0.3)',
    },
    sectionTitle: {
      fontSize: '24px',
      fontWeight: '700',
      marginBottom: '24px',
      display: 'flex',
      alignItems: 'center',
      gap: '12px'
    },
    inputGroup: {
      marginBottom: '20px'
    },
    label: {
      display: 'block',
      fontSize: '14px',
      fontWeight: '600',
      color: '#cbd5e1',
      marginBottom: '12px'
    },
    dropdown: {
      width: '100%',
      padding: '14px',
      background: 'rgba(15, 23, 42, 0.5)',
      border: '1px solid rgba(100,116,139,0.3)',
      borderRadius: '12px',
      color: 'white',
      fontSize: '14px',
      cursor: 'pointer'
    },
    textarea: {
      width: '100%',
      minHeight: '150px',
      padding: '14px',
      background: 'rgba(15, 23, 42, 0.5)',
      border: '1px solid rgba(100,116,139,0.3)',
      borderRadius: '12px',
      color: 'white',
      fontSize: '14px',
      fontFamily: 'inherit',
      resize: 'vertical'
    },
    uploadBox: {
      border: '2px dashed rgba(100,116,139,0.5)',
      borderRadius: '12px',
      padding: '32px',
      textAlign: 'center',
      cursor: 'pointer',
      transition: 'all 0.3s ease'
    },
    checkButton: {
      width: '100%',
      padding: '18px',
      background: 'linear-gradient(135deg, #22d3ee 0%, #3b82f6 100%)',
      border: 'none',
      borderRadius: '12px',
      color: 'white',
      fontSize: '18px',
      fontWeight: '700',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      boxShadow: '0 4px 12px rgba(34, 211, 238, 0.3)',
      marginTop: '32px'
    },
    resultSection: {
      background: 'rgba(30, 41, 59, 0.6)',
      backdropFilter: 'blur(10px)',
      padding: '40px',
      borderRadius: '24px',
      border: '1px solid rgba(100,116,139,0.3)',
      marginTop: '32px'
    },
    scoreGrid: {
      display: 'grid',
      gridTemplateColumns: '1fr 1fr',
      gap: '24px',
      marginBottom: '32px'
    },
    scoreCard: {
      background: 'rgba(51, 65, 85, 0.5)',
      padding: '24px',
      borderRadius: '16px',
      textAlign: 'center'
    },
    explanationBox: {
      background: 'rgba(15, 23, 42, 0.5)',
      padding: '24px',
      borderRadius: '16px',
      lineHeight: '1.8',
      color: '#cbd5e1'
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Check Eligibility</h1>

      {/* Two Column Layout - Patient & Trial */}
      <div style={styles.twoColumnGrid}>
        {/* PATIENT SECTION */}
        <div style={styles.section}>
          <div style={styles.sectionTitle}>
            <FileText size={28} color="#22d3ee" />
            Patient Information
          </div>

          {/* Patient Dropdown */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Select Existing Patient</label>
            <select
              style={styles.dropdown}
              value={selectedPatientId}
              onChange={(e) => {
                setSelectedPatientId(e.target.value);
                if (e.target.value) {
                  setPatientMode('dropdown');
                  setPatientText('');
                  setPatientFile(null);
                }
              }}
            >
              <option value="">-- Choose a patient --</option>
              {patients.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name} ({p.age}y, {p.gender})
                </option>
              ))}
            </select>
          </div>

          <div style={{ textAlign: 'center', margin: '20px 0', color: '#94a3b8' }}>OR</div>

          {/* Patient Text Input */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Enter Patient Data (Text)</label>
            <textarea
              style={styles.textarea}
              placeholder="Paste patient information here...&#10;Example:&#10;Name: John Doe&#10;Age: 45&#10;Gender: Male&#10;Conditions: Diabetes, Hypertension&#10;Medications: Metformin, Amlodipine&#10;HbA1c: 7.8%"
              value={patientText}
              onChange={(e) => {
                setPatientText(e.target.value);
                if (e.target.value) {
                  setPatientMode('text');
                  setSelectedPatientId('');
                  setPatientFile(null);
                }
              }}
            />
          </div>

          <div style={{ textAlign: 'center', margin: '20px 0', color: '#94a3b8' }}>OR</div>

          {/* Patient PDF Upload */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Upload Patient PDF</label>
            <label htmlFor="patient-pdf">
              <div style={{
                ...styles.uploadBox,
                borderColor: patientFile ? '#22d3ee' : 'rgba(100,116,139,0.5)'
              }}>
                <Upload size={40} style={{ margin: '0 auto 12px', opacity: 0.6 }} />
                <div>{patientFile ? patientFile.name : 'Click to upload PDF'}</div>
              </div>
            </label>
            <input
              id="patient-pdf"
              type="file"
              accept=".pdf"
              onChange={(e) => {
                setPatientFile(e.target.files[0]);
                if (e.target.files[0]) {
                  setPatientMode('pdf');
                  setSelectedPatientId('');
                  setPatientText('');
                }
              }}
              style={{ display: 'none' }}
            />
          </div>
        </div>

        {/* TRIAL SECTION */}
        <div style={styles.section}>
          <div style={styles.sectionTitle}>
            <FileText size={28} color="#8b5cf6" />
            Trial Protocol
          </div>

          {/* Trial Dropdown */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Select Existing Trial</label>
            <select
              style={styles.dropdown}
              value={selectedTrialId}
              onChange={(e) => {
                setSelectedTrialId(e.target.value);
                if (e.target.value) {
                  setTrialMode('dropdown');
                  setTrialText('');
                  setTrialFile(null);
                }
              }}
            >
              <option value="">-- Choose a trial --</option>
              {trials.map((t) => (
                <option key={t.id} value={t.id}>
                  {t.title} ({t.condition})
                </option>
              ))}
            </select>
          </div>

          <div style={{ textAlign: 'center', margin: '20px 0', color: '#94a3b8' }}>OR</div>

          {/* Trial Text Input */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Enter Trial Criteria (Text)</label>
            <textarea
              style={styles.textarea}
              placeholder="Paste trial inclusion/exclusion criteria...&#10;Example:&#10;Inclusion Criteria:&#10;- Age 18-75 years&#10;- Type 2 Diabetes diagnosis&#10;- HbA1c 7-10%&#10;&#10;Exclusion Criteria:&#10;- Pregnant or breastfeeding&#10;- Severe kidney disease"
              value={trialText}
              onChange={(e) => {
                setTrialText(e.target.value);
                if (e.target.value) {
                  setTrialMode('text');
                  setSelectedTrialId('');
                  setTrialFile(null);
                }
              }}
            />
          </div>

          <div style={{ textAlign: 'center', margin: '20px 0', color: '#94a3b8' }}>OR</div>

          {/* Trial PDF Upload */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Upload Trial PDF</label>
            <label htmlFor="trial-pdf">
              <div style={{
                ...styles.uploadBox,
                borderColor: trialFile ? '#8b5cf6' : 'rgba(100,116,139,0.5)'
              }}>
                <Upload size={40} style={{ margin: '0 auto 12px', opacity: 0.6 }} />
                <div>{trialFile ? trialFile.name : 'Click to upload PDF'}</div>
              </div>
            </label>
            <input
              id="trial-pdf"
              type="file"
              accept=".pdf"
              onChange={(e) => {
                setTrialFile(e.target.files[0]);
                if (e.target.files[0]) {
                  setTrialMode('pdf');
                  setSelectedTrialId('');
                  setTrialText('');
                }
              }}
              style={{ display: 'none' }}
            />
          </div>
        </div>
      </div>

      {/* Error Display */}
      {error && (
        <div style={{
          background: 'rgba(239, 68, 68, 0.1)',
          border: '1px solid rgba(239, 68, 68, 0.3)',
          borderRadius: '12px',
          padding: '16px',
          marginBottom: '24px',
          color: '#fca5a5'
        }}>
          ⚠️ {error}
        </div>
      )}

      {/* Check Button */}
      <button
        style={styles.checkButton}
        onClick={handleCheck}
        disabled={loading}
        onMouseEnter={(e) => {
          if (!loading) {
            e.target.style.transform = 'translateY(-2px)';
            e.target.style.boxShadow = '0 8px 20px rgba(34, 211, 238, 0.4)';
          }
        }}
        onMouseLeave={(e) => {
          e.target.style.transform = 'translateY(0)';
          e.target.style.boxShadow = '0 4px 12px rgba(34, 211, 238, 0.3)';
        }}
      >
        {loading ? '🔄 Checking Eligibility...' : '✓ Check Eligibility'}
      </button>

      {/* Results Section */}
      {result && (
        <div style={styles.resultSection}>
          {/* Status Badge */}
          <div style={{ textAlign: 'center', marginBottom: '32px' }}>
            <div style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: '12px',
              padding: '16px 32px',
              background: `${getStatusColor(result.status)}22`,
              border: `2px solid ${getStatusColor(result.status)}`,
              borderRadius: '16px'
            }}>
              {React.createElement(getStatusIcon(result.status), {
                size: 32,
                color: getStatusColor(result.status)
              })}
              <span style={{
                fontSize: '28px',
                fontWeight: '800',
                color: getStatusColor(result.status),
                textTransform: 'uppercase'
              }}>
                {result.status.replace('_', ' ')}
              </span>
            </div>
          </div>

          {/* Confidence Scores */}
          <div style={styles.scoreGrid}>
            <div style={styles.scoreCard}>
              <div style={{ fontSize: '14px', color: '#94a3b8', marginBottom: '8px', textTransform: 'uppercase' }}>
                Overall Score
              </div>
              <div style={{ fontSize: '48px', fontWeight: '800', color: '#22d3ee' }}>
                {(result.overall_score * 100).toFixed(1)}%
              </div>
            </div>
            <div style={styles.scoreCard}>
              <div style={{ fontSize: '14px', color: '#94a3b8', marginBottom: '8px', textTransform: 'uppercase' }}>
                Confidence
              </div>
              <div style={{ fontSize: '48px', fontWeight: '800', color: '#8b5cf6' }}>
                {result.confidence_score.toFixed(1)}%
              </div>
            </div>
          </div>

          {/* Explanation */}
          <div>
            <h3 style={{ fontSize: '20px', fontWeight: '700', marginBottom: '16px', color: '#22d3ee' }}>
              📋 Explanation (ML-Generated)
            </h3>
            <div style={styles.explanationBox}>
              {result.explanation}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default EligibilityChecker;
